import{_ as e}from"./前端项目服务器目录-3544a7db.js";import{_ as a,p as s,q as n,a1 as i}from"./framework-d7d41868.js";const c={},d=i('<h1 id="生产与部署" tabindex="-1"><a class="header-anchor" href="#生产与部署" aria-hidden="true">#</a> 生产与部署</h1><p>基座应用和微应用都采用 <code>服务器/项目名</code> 的二级目录进行部署</p><div class="custom-container tip"><p class="custom-container-title">重要</p><p>如果微应用没有和基座应用部署在同一根目录下，微应用部署的服务器要配置允许跨域访问</p><p>因为基座应用要加载微应用的资源，如果微应用的服务器没有配置允许跨域访问，就加载不到微应用，访问出错</p></div><p>一个前端部署目录如下：</p><p><img src="'+e+`" alt="前端项目服务器目录.png"></p><h2 id="微应用打包" tabindex="-1"><a class="header-anchor" href="#微应用打包" aria-hidden="true">#</a> 微应用打包</h2><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">npm</span> run build
<span class="token comment"># 或</span>
<span class="token function">yarn</span> build
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>运行打包命令后，框架会以当前系统的命名（package.json 内的 name 属性）为输出目录打包出生产包，且会自动打包出一个 .zip 的压缩包，方便投产</p><h2 id="基座应用" tabindex="-1"><a class="header-anchor" href="#基座应用" aria-hidden="true">#</a> 基座应用</h2><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>基座应用暂时都由架构组维护，需要更新时，会给到各组生产包，以进行投产</p><p>视情况是否对外开发基座应用的代码</p></div><p>基座应用打包&amp;部署与微应用同理</p><h2 id="关于打包静态资源优化" tabindex="-1"><a class="header-anchor" href="#关于打包静态资源优化" aria-hidden="true">#</a> 关于打包静态资源优化</h2><p>本身每个微应用是需要加载一些第三方依赖的，如： <code>vue</code> / <code>vuex</code> / <code>vue-router</code> / <code>jn-ve-global</code> ...</p><p>这些第三方依赖会加大应用的打包体积，会造成如下负面影响：</p><ul><li>生产包的体积过大，影响基座应用加载微应用的时间（体积越大，加载越慢，造成卡死现象）</li><li>这些资源基座应用实际已经加载过了，微应用都是重复加载，无意义</li></ul><p>基座应用框架与微应用框架都采用了 webpack 的 <code>externals</code> ，以排除生产包中的重复第三方依赖，以减小打包体积。</p><p>而那些共享的第三方依赖，都提取到了基座应用中，作为静态资源加载到应用中</p><p>细心的同学可能注意到，基座应用打出来的包有好几十M，而微应用只有几百k，抽取公用依赖后，微应用的生产包只剩下了自己应用的业务模块</p><h3 id="微应用引用" tabindex="-1"><a class="header-anchor" href="#微应用引用" aria-hidden="true">#</a> 微应用引用</h3><p>微应用在 <code>index.html</code> 中，会引用基座应用生产包下的 <code>lib/xxxxx</code> 资源，<strong style="color:#ff3040;">所以一定要将基座应用的部署位置告诉微应用</strong></p><p>通过环境变量 <code>VUE_APP_BASE_APP_SERVER</code> 配置</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 基座应用部署位置，用来加载静态共享资源，静态共享资源存在于基座应用中</span>
<span class="token assign-left variable">VUE_APP_BASE_APP_SERVER</span><span class="token operator">=</span>http://172.31.33.84/basic
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="组件库更新" tabindex="-1"><a class="header-anchor" href="#组件库更新" aria-hidden="true">#</a> 组件库更新</h3><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>由于现在第三方依赖都提取到了基座应用中，所以组件的库的后续更新，都将体现在基座应用中，组件库更新时，我会给到各组新的基座应用（主要是新的组件库静态资源）</p></div>`,24),t=[d];function o(r,p){return s(),n("div",null,t)}const u=a(c,[["render",o],["__file","production.html.vue"]]);export{u as default};
